import { parseCSV } from './csv-parser';

function assert(condition: boolean, message?: string): void {
  if (!condition) {
    throw new Error(message ?? 'Assertion failed');
  }
}

function testBasicParsing(): void {
  const csv = 'name,age\nAlice,30\nBob,25';
  const result = parseCSV(csv);

  assert(result.headers.length === 2, 'Expected two headers');
  assert(result.headers[0] === 'name', 'First header should be name');
  assert(result.headers[1] === 'age', 'Second header should be age');
  assert(result.rows.length === 2, 'Expected two data rows');
  assert(result.rows[0].name === 'Alice', 'First row name mismatch');
  assert(result.rows[0].age === 30, 'First row age should be numeric 30');
  assert(result.rows[1].name === 'Bob', 'Second row name mismatch');
  assert(result.rows[1].age === 25, 'Second row age should be numeric 25');
  assert(result.errors.length === 0, 'No errors expected on well-formed CSV');
}

function testQuotedFieldsHandling(): void {
  const csv = 'name,notes\n"Smith, John","Hello, world"\n"Jane","Embedded, comma"';
  const result = parseCSV(csv);

  assert(result.rows.length === 2, 'Expected two rows');
  assert(result.rows[0].name === 'Smith, John', 'Quoted name should include comma');
  assert(result.rows[0].notes === 'Hello, world', 'Quoted field should preserve comma');
  assert(result.rows[1].notes === 'Embedded, comma', 'Quoted field should keep comma');
}

function testEscapedQuotes(): void {
  const csv = 'quote\n"She said, ""Hi"""';
  const result = parseCSV(csv);

  assert(result.rows.length === 1, 'One row expected');
  assert(result.rows[0].quote === 'She said, "Hi"', 'Escaped quotes should collapse to single literal');
}

function testCustomDelimiterQuoteAndLineSeparator(): void {
  const csv = 'name;note;score~Alice;' + "'Includes;delimiter'" + ';10~Bob;' + "'Simple'" + ';5';
  const result = parseCSV(csv, { delimiter: ';', quote: '\'', lineSeparator: '~' });

  assert(result.rows.length === 2, 'Two rows expected in custom-delimited CSV');
  assert(result.rows[0].note === 'Includes;delimiter', 'Quoted note should contain delimiter characters');
  assert(result.rows[0].score === 10, 'Score should parse as number');
  assert(result.rows[1].note === 'Simple', 'Second note should parse correctly');
  assert(result.rows[1].score === 5, 'Second score should parse as number');
}

function testTypeCoercion(): void {
  const csv = 'number,float,bool,boolFalse,nullish,empty,text\n42,3.5,true,false,NULL,,Hello';
  const result = parseCSV(csv);
  const row = result.rows[0];

  assert(typeof row.number === 'number' && row.number === 42, 'Integer should be coerced');
  assert(typeof row.float === 'number' && row.float === 3.5, 'Float should be coerced');
  assert(row.bool === true, 'True should coerce to boolean true');
  assert(row.boolFalse === false, 'False should coerce to boolean false');
  assert(row.nullish === null, 'NULL should coerce to null');
  assert(row.empty === null, 'Empty field should coerce to null');
  assert(row.text === 'Hello', 'Unmatched text should remain string');
}

function testMalformedRowsAreReported(): void {
  const csv = 'name,age\nAlice,30,extra\nBob,25';
  const result = parseCSV(csv);

  assert(result.errors.length === 1, 'One malformed row expected');
  assert(result.errors[0].row === 2, 'Malformed row should reference the correct line number');
  assert(result.rows.length === 1, 'Only well-formed rows should be returned');
  assert(result.rows[0].name === 'Bob', 'Only second row should survive');
}

function testFilteringAndAggregation(): void {
  const csv = 'name,team,score\nAlice,A,10\nBob,B,20\nCarol,A,30\nDave,B,40';
  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.team === 'A');
  assert(filtered.rows.length === 2, 'Filtered result should only have matching rows');
  assert(filtered.sum('score') === 40, 'Sum of filtered scores should be 40');
  assert(filtered.average('score') === 20, 'Average of filtered scores should be 20');

  assert(result.sum('score') === 100, 'Sum of all scores should be 100');
  assert(result.average('score') === 25, 'Average of all scores should be 25');
  assert(result.count() === 4, 'Count should reflect total rows');
  assert(result.average('name') === null, 'Non-numeric column should yield null average');

  const groups = result.groupBy('team');
  assert(groups.get('A')?.length === 2, 'Group A should have two members');
  assert(groups.get('B')?.length === 2, 'Group B should have two members');
  assert(groups.get('A')?.[0].name === 'Alice', 'Group entries should maintain original data');
}

function testEdgeCases(): void {
  const empty = parseCSV('');
  assert(empty.rows.length === 0, 'Empty input should yield no rows');
  assert(empty.headers.length === 0, 'Empty input should yield no headers');
  assert(empty.errors.length === 0, 'Empty input should produce no errors');

  const singleColumn = parseCSV('only\nvalue');
  assert(singleColumn.headers.length === 1 && singleColumn.headers[0] === 'only', 'Single header should parse');
  assert(singleColumn.rows.length === 1, 'Single data row expected');
  assert(singleColumn.rows[0].only === 'value', 'Single value should survive');

  const onlyHeader = parseCSV('solo');
  assert(onlyHeader.headers.length === 1, 'Single header should still exist');
  assert(onlyHeader.rows.length === 0, 'No data rows should exist');

  const longText = 'x'.repeat(12000);
  const largeCsv = `id,text\n1,"${longText}"`;
  const largeResult = parseCSV(largeCsv);
  assert(largeResult.rows.length === 1, 'Large field should still parse to a single row');
  assert(largeResult.rows[0].text === longText, 'Large quoted field content should be preserved');
}

function runTests(): void {
  testBasicParsing();
  testQuotedFieldsHandling();
  testEscapedQuotes();
  testCustomDelimiterQuoteAndLineSeparator();
  testTypeCoercion();
  testMalformedRowsAreReported();
  testFilteringAndAggregation();
  testEdgeCases();
  console.log('All CSV parser tests passed');
}

runTests();

