export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number | null;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

class CSVResultImpl implements CSVResult {
  constructor(
    public readonly rows: Record<string, any>[],
    public readonly headers: string[],
    public readonly errors: CSVError[]
  ) {}

  filter(predicate: (row: Record<string, any>) => boolean): CSVResult {
    const filtered = this.rows.filter(predicate);
    return new CSVResultImpl(filtered, this.headers, this.errors);
  }

  sum(column: string): number {
    let total = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === 'number' && Number.isFinite(value)) {
        total += value;
      }
    }
    return total;
  }

  average(column: string): number | null {
    let total = 0;
    let count = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === 'number' && Number.isFinite(value)) {
        total += value;
        count += 1;
      }
    }
    if (count === 0) {
      return null;
    }
    return total / count;
  }

  count(): number {
    return this.rows.length;
  }

  groupBy(column: string): Map<any, Record<string, any>[]> {
    const groups = new Map<any, Record<string, any>[]>();
    for (const row of this.rows) {
      const key = row[column];
      const bucket = groups.get(key);
      if (bucket) {
        bucket.push(row);
      } else {
        groups.set(key, [row]);
      }
    }
    return groups;
  }
}

function coerceValue(raw: string): any {
  const trimmed = raw.trim();
  if (trimmed === '') {
    return null;
  }
  const normalized = trimmed.toLowerCase();
  if (normalized === 'null') {
    return null;
  }
  if (normalized === 'true') {
    return true;
  }
  if (normalized === 'false') {
    return false;
  }

  const numberPattern = /^-?(?:\d+|\d*\.\d+)$/;
  if (numberPattern.test(trimmed)) {
    const num = Number(trimmed);
    if (Number.isFinite(num)) {
      return num;
    }
  }

  return raw;
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quote = options.quote ?? '"';
  let lineSeparator = options.lineSeparator;

  let normalizedInput = input ?? '';
  if (lineSeparator === undefined) {
    normalizedInput = normalizedInput.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
    lineSeparator = '\n';
  }

  if (normalizedInput.length === 0) {
    return new CSVResultImpl([], [], []);
  }

  const records: { fields: string[]; line: number }[] = [];
  let currentRow: string[] = [];
  let currentField = '';
  let inQuotes = false;
  let pos = 0;
  let currentLine = 1;
  let unterminatedQuoteLine: number | null = null;

  const lineSepLength = lineSeparator.length;
  const matchesLineSeparator = (index: number): boolean => {
    if (lineSepLength === 0) {
      return false;
    }
    if (index + lineSepLength > normalizedInput.length) {
      return false;
    }
    return normalizedInput.substr(index, lineSepLength) === lineSeparator;
  };

  while (pos < normalizedInput.length) {
    const char = normalizedInput[pos];

    if (inQuotes) {
      if (char === quote) {
        const nextChar = normalizedInput[pos + 1];
        if (nextChar === quote) {
          currentField += quote;
          pos += 2;
          continue;
        }
        inQuotes = false;
        pos += 1;
        continue;
      }

      if (matchesLineSeparator(pos)) {
        currentField += lineSeparator;
        pos += lineSepLength;
        continue;
      }

      currentField += char;
      pos += 1;
      continue;
    }

    if (char === quote) {
      inQuotes = true;
      pos += 1;
      continue;
    }

    if (matchesLineSeparator(pos)) {
      currentRow.push(currentField);
      currentField = '';
      records.push({ fields: currentRow, line: currentLine });
      currentRow = [];
      pos += lineSepLength;
      currentLine += 1;
      continue;
    }

    if (char === delimiter) {
      currentRow.push(currentField);
      currentField = '';
      pos += 1;
      continue;
    }

    currentField += char;
    pos += 1;
  }

  if (inQuotes && unterminatedQuoteLine === null) {
    unterminatedQuoteLine = currentLine;
  }

  currentRow.push(currentField);

  if (currentRow.length > 0 || currentField.length > 0) {
    records.push({ fields: currentRow, line: currentLine });
  }

  if (records.length === 0) {
    return new CSVResultImpl([], [], []);
  }

  const headers = records[0].fields.slice();
  const headerCount = headers.length;
  const rows: Record<string, any>[] = [];
  const errors: CSVError[] = [];

  if (unterminatedQuoteLine !== null) {
    errors.push({
      row: unterminatedQuoteLine,
      message: 'Unterminated quoted field',
    });
  }

  for (let i = 1; i < records.length; i += 1) {
    const record = records[i];
    if (record.fields.length !== headerCount) {
      errors.push({
        row: record.line,
        message: `Malformed row: expected ${headerCount} columns but got ${record.fields.length}`,
      });
      continue;
    }

    const rowObject: Record<string, any> = {};
    for (let col = 0; col < headerCount; col += 1) {
      const header = headers[col];
      rowObject[header] = coerceValue(record.fields[col]);
    }
    rows.push(rowObject);
  }

  return new CSVResultImpl(rows, headers, errors);
}
